"""
Async HomeKit controller + WebSocket bridge for PG3x.

Runs on a dedicated asyncio loop (see Controller). Do not import udi_interface here.
"""
from __future__ import annotations

import asyncio
import json
import logging
from typing import Any, Callable, Optional

import websockets
from websockets.server import WebSocketServerProtocol

from aiohomekit import Controller as HKController
from aiohomekit.model.characteristics import CharacteristicPermissions, CharacteristicsTypes
from aiohomekit.model.status_flags import StatusFlags
from aiohomekit.uuid import normalize_uuid

PROTOCOL_VERSION = "1"
PAIRING_ALIAS = "default"
DATA_KEY_PAIRING = "homekit_pairing"


def _build_uuid_to_char_name() -> dict[str, str]:
    mapping: dict[str, str] = {}
    for attr, val in vars(CharacteristicsTypes).items():
        if attr.startswith("_") or not isinstance(val, str):
            continue
        mapping[normalize_uuid(val)] = attr
    return mapping


_UUID_TO_NAME = _build_uuid_to_char_name()


def characteristic_label(type_uuid: str) -> str:
    nu = normalize_uuid(type_uuid)
    return _UUID_TO_NAME.get(nu, nu)


def _parse_char_name_to_uuid(spec: str) -> str:
    spec = spec.strip()
    if hasattr(CharacteristicsTypes, spec):
        return normalize_uuid(getattr(CharacteristicsTypes, spec))
    return normalize_uuid(spec)


def _resolve_aid_iid(pairing, char_spec: str) -> Optional[tuple[int, int]]:
    uid = _parse_char_name_to_uuid(char_spec)
    if not pairing.accessories:
        return None
    for acc in pairing.accessories:
        for svc in acc.services:
            for ch in svc.characteristics:
                if normalize_uuid(ch.type) == uid:
                    return acc.aid, ch.iid
    return None


def _subscribable_characteristics(pairing) -> list[tuple[int, int]]:
    out: list[tuple[int, int]] = []
    if not pairing.accessories:
        return out
    for acc in pairing.accessories:
        aid = acc.aid
        for svc in acc.services:
            for ch in svc.characteristics:
                if CharacteristicPermissions.events in ch.perms:
                    out.append((aid, ch.iid))
    return out


class HomeKitHubBridge:
    """One pairing, one WebSocket server, fan-out events."""

    def __init__(
        self,
        logger: logging.Logger,
        get_params: Callable[[], dict[str, Any]],
        get_custom_data: Callable[[], dict[str, Any]],
        set_custom_data: Callable[[dict[str, Any]], None],
    ) -> None:
        self.log = logger
        self._get_params = get_params
        self._get_custom_data = get_custom_data
        self._set_custom_data = set_custom_data

        self._hk: Optional[HKController] = None
        self._pairing_alias = PAIRING_ALIAS
        self._stop_listening: Optional[Callable[[], None]] = None
        self._clients: set[WebSocketServerProtocol] = set()
        self._ws_server = None
        self._running = False

    def _pairing(self):
        if not self._hk:
            return None
        return self._hk.aliases.get(self._pairing_alias)

    async def start(self) -> None:
        if self._running:
            return
        self._running = True
        self._hk = HKController()
        await self._hk.async_start()
        await self._start_websocket_server()
        await self._sync_pairing_from_params()

    async def stop(self) -> None:
        self._running = False
        await self._shutdown_pairing_session()
        if self._ws_server is not None:
            self._ws_server.close()
            await self._ws_server.wait_closed()
            self._ws_server = None
        if self._hk:
            await self._hk.async_stop()
            self._hk = None
        self._clients.clear()

    async def restart_session(self) -> None:
        """Reload pairing from params + customData (after PG3 param change)."""
        await self._shutdown_pairing_session()
        await self._sync_pairing_from_params()

    async def discover_log(self, timeout: float = 12.0) -> None:
        if not self._hk:
            return
        self.log.info("HomeKit discovery (%.1fs)...", timeout)
        try:
            async with asyncio.timeout(timeout):
                async for discovery in self._hk.async_discover():
                    d = discovery.description
                    flags = d.status_flags if d else None
                    paired = bool(flags and not (flags & StatusFlags.UNPAIRED))
                    self.log.info(
                        "HAP accessory: name=%r id=%s paired=%s",
                        d.name if d else None,
                        d.id if d else None,
                        paired,
                    )
        except TimeoutError:
            self.log.info("Discovery window ended")
        except Exception:
            self.log.exception("Discovery failed")

    def _ws_bind(self) -> tuple[str, int]:
        p = self._get_params()
        host = (p.get("ws_host") or "127.0.0.1").strip()
        try:
            port = int(p.get("ws_port") or 8163)
        except (TypeError, ValueError):
            port = 8163
        return host, port

    async def _start_websocket_server(self) -> None:
        host, port = self._ws_bind()
        self.log.info("WebSocket server listening on %s:%s", host, port)
        self._ws_server = await websockets.serve(
            self._ws_connection,
            host,
            port,
            ping_interval=20,
            ping_timeout=20,
        )

    async def _ws_connection(self, ws: WebSocketServerProtocol) -> None:
        self._clients.add(ws)
        self.log.debug("WS client connected from %s", ws.remote_address)
        try:
            async for raw in ws:
                await self._handle_ws_message(ws, raw)
        except websockets.ConnectionClosed:
            pass
        except Exception:
            self.log.exception("WebSocket handler error")
        finally:
            self._clients.discard(ws)

    async def _handle_ws_message(self, ws: WebSocketServerProtocol, raw: str) -> None:
        try:
            msg = json.loads(raw)
        except json.JSONDecodeError:
            await self._send_ws(
                ws,
                {
                    "version": PROTOCOL_VERSION,
                    "action": "error",
                    "message": "invalid json",
                },
            )
            return
        ver = msg.get("version")
        if ver != PROTOCOL_VERSION:
            await self._send_ws(
                ws,
                {
                    "version": PROTOCOL_VERSION,
                    "action": "error",
                    "message": f"unsupported version {ver!r}, need {PROTOCOL_VERSION}",
                },
            )
            await ws.close()
            return
        action = msg.get("action")
        if action == "hello":
            await self._send_ws(
                ws,
                {
                    "version": PROTOCOL_VERSION,
                    "action": "ack",
                    "protocol": PROTOCOL_VERSION,
                },
            )
            return
        if action == "command":
            await self._handle_command(ws, msg)
            return
        await self._send_ws(
            ws,
            {
                "version": PROTOCOL_VERSION,
                "action": "error",
                "message": f"unknown action {action!r}",
            },
        )

    async def _handle_command(self, ws: WebSocketServerProtocol, msg: dict) -> None:
        device_id = (msg.get("device_id") or "").strip().lower()
        char_spec = msg.get("characteristic")
        value = msg.get("value")
        pairing = self._pairing()
        if not pairing:
            await self._send_ws(
                ws,
                {
                    "version": PROTOCOL_VERSION,
                    "action": "error",
                    "for": "command",
                    "message": "no active pairing",
                },
            )
            return
        if pairing.id.lower() != device_id:
            await self._send_ws(
                ws,
                {
                    "version": PROTOCOL_VERSION,
                    "action": "error",
                    "for": "command",
                    "message": "device_id mismatch",
                },
            )
            return
        if not isinstance(char_spec, str):
            await self._send_ws(
                ws,
                {
                    "version": PROTOCOL_VERSION,
                    "action": "error",
                    "for": "command",
                    "message": "characteristic must be string",
                },
            )
            return
        resolved = _resolve_aid_iid(pairing, char_spec)
        if not resolved:
            await self._send_ws(
                ws,
                {
                    "version": PROTOCOL_VERSION,
                    "action": "error",
                    "for": "command",
                    "message": f"unknown characteristic {char_spec!r}",
                },
            )
            return
        aid, iid = resolved
        try:
            err = await pairing.put_characteristics([(aid, iid, value)])
            if err:
                await self._send_ws(
                    ws,
                    {
                        "version": PROTOCOL_VERSION,
                        "action": "error",
                        "for": "command",
                        "message": str(err),
                    },
                )
                return
        except Exception as ex:
            self.log.exception("put_characteristics failed")
            await self._send_ws(
                ws,
                {
                    "version": PROTOCOL_VERSION,
                    "action": "error",
                    "for": "command",
                    "message": str(ex),
                },
            )
            return
        await self._send_ws(
            ws,
            {"version": PROTOCOL_VERSION, "action": "ack", "for": "command"},
        )

    async def _send_ws(self, ws: WebSocketServerProtocol, obj: dict) -> None:
        try:
            await ws.send(json.dumps(obj, default=str))
        except Exception:
            pass

    async def _broadcast(self, obj: dict) -> None:
        line = json.dumps(obj, default=str)
        dead: list[WebSocketServerProtocol] = []
        for ws in list(self._clients):
            try:
                await ws.send(line)
            except Exception:
                dead.append(ws)
        for ws in dead:
            self._clients.discard(ws)

    def _on_hap_event(self, ev: dict) -> None:
        pairing = self._pairing()
        if not pairing or not pairing.accessories:
            return
        if not ev:
            return
        device_id = pairing.id.lower()
        try:
            loop = asyncio.get_running_loop()
        except RuntimeError:
            return

        for key, payload in ev.items():
            if not isinstance(key, tuple) or len(key) != 2:
                continue
            aid, iid = key
            if "value" not in payload:
                continue
            try:
                ch = pairing.accessories.aid(aid).characteristics.iid(iid)
                label = characteristic_label(ch.type)
            except Exception:
                label = f"{aid}.{iid}"
            loop.create_task(
                self._broadcast(
                    {
                        "version": PROTOCOL_VERSION,
                        "action": "event",
                        "device_id": device_id,
                        "characteristic": label,
                        "aid": aid,
                        "iid": iid,
                        "value": payload.get("value"),
                    }
                )
            )

    async def _shutdown_pairing_session(self) -> None:
        if self._stop_listening:
            try:
                self._stop_listening()
            except Exception:
                pass
            self._stop_listening = None
        pairing = self._pairing()
        if pairing:
            try:
                await pairing.close()
            except Exception:
                self.log.exception("pairing close")
        if self._hk and self._pairing_alias in self._hk.aliases:
            try:
                self._hk.aliases.pop(self._pairing_alias, None)
                pid = None
                for k, p in list(self._hk.pairings.items()):
                    if self._pairing_alias in str(k):
                        pid = k
                        break
                for k in list(self._hk.pairings.keys()):
                    self._hk.pairings.pop(k, None)
            except Exception:
                self.log.exception("controller pairing cleanup")

    async def _sync_pairing_from_params(self) -> None:
        params = self._get_params()
        pin = (params.get("hap_pin") or "").strip()
        data = self._get_custom_data()
        saved = data.get(DATA_KEY_PAIRING)

        if not pin:
            if saved:
                self._clear_saved_pairing()
            self.log.info("hap_pin empty — not paired; clear pairing state if any")
            await self._try_remove_accessory_pairing()
            return

        if saved and isinstance(saved, dict) and saved.get("AccessoryPairingID"):
            try:
                self._hk.load_pairing(self._pairing_alias, saved)
                pairing = self._pairing()
                if pairing:
                    await self._activate_pairing(pairing)
                return
            except Exception:
                self.log.exception("load_pairing failed; will try new pairing")
                self._clear_saved_pairing()

        await self._pair_with_pin(pin, params)

    def _clear_saved_pairing(self) -> None:
        data = dict(self._get_custom_data())
        data.pop(DATA_KEY_PAIRING, None)
        self._set_custom_data(data)

    async def _try_remove_accessory_pairing(self) -> None:
        """Best-effort unpair from accessory when user clears PIN."""
        data = self._get_custom_data()
        saved = data.get(DATA_KEY_PAIRING)
        if not saved or not isinstance(saved, dict):
            return
        try:
            self._hk.load_pairing(self._pairing_alias, saved)
            pairing = self._pairing()
            if pairing:
                ios_id = saved.get("iOSPairingId")
                if ios_id:
                    await pairing.remove_pairing(ios_id)
        except Exception:
            self.log.warning("remove_pairing failed (device may be offline)", exc_info=True)
        finally:
            await self._shutdown_pairing_session()
            self._clear_saved_pairing()

    async def _pair_with_pin(self, pin: str, params: dict) -> None:
        accessory_id = (params.get("accessory_id") or "").strip().lower()
        accessory_name = (params.get("accessory_name") or "").strip()

        matched = None
        try:
            async with asyncio.timeout(30):
                async for discovery in self._hk.async_discover():
                    d = discovery.description
                    if not d:
                        continue
                    if accessory_id and d.id.lower() != accessory_id:
                        continue
                    if accessory_name and accessory_name.lower() not in (d.name or "").lower():
                        continue
                    if discovery.paired:
                        self.log.warning(
                            "Skipping %s (%s): already paired elsewhere",
                            d.name,
                            d.id,
                        )
                        continue
                    matched = discovery
                    break
        except TimeoutError:
            self.log.error("Pairing discovery timed out")
            return

        if not matched:
            self.log.error("No unpaired HomeKit accessory matched id=%r name=%r", accessory_id, accessory_name)
            return

        try:
            finish = await matched.async_start_pairing(self._pairing_alias)
            pairing = await finish(pin)
        except Exception:
            self.log.exception("Pairing failed")
            return

        pdata = dict(pairing.pairing_data)
        self._persist_pairing(pdata)
        await self._activate_pairing(pairing)

    def _persist_pairing(self, pdata: dict) -> None:
        data = dict(self._get_custom_data())
        data[DATA_KEY_PAIRING] = pdata
        self._set_custom_data(data)
        self.log.info("Saved pairing for accessory %s", pdata.get("AccessoryPairingID"))

    async def _activate_pairing(self, pairing) -> None:
        if self._stop_listening:
            self._stop_listening()
        self._stop_listening = pairing.dispatcher_connect(self._on_hap_event)
        try:
            await pairing.list_accessories_and_characteristics()
        except Exception:
            self.log.exception("list_accessories_and_characteristics")
            return
        to_sub = _subscribable_characteristics(pairing)
        if to_sub:
            try:
                await pairing.subscribe(to_sub)
                self.log.info("Subscribed to %d event characteristics", len(to_sub))
            except Exception:
                self.log.exception("subscribe failed")
        self.log.info("HomeKit session active for %s", pairing.id)

"""
Async HomeKit controller + WebSocket bridge for PG3x.

Runs on a dedicated asyncio loop (see nodes.Controller). No udi_interface imports.
"""
from __future__ import annotations

import asyncio
import json
import logging
from typing import Any, Callable, Optional

import websockets

from aiohomekit import Controller as HKController
from aiohomekit.model.characteristics import CharacteristicPermissions, CharacteristicsTypes
from aiohomekit.model.status_flags import StatusFlags
from aiohomekit.uuid import normalize_uuid

PROTOCOL_VERSION = "1"
PAIRING_ALIAS = "default"
DATA_KEY_PAIRING = "homekit_pairing"


def _build_uuid_to_char_name() -> dict[str, str]:
    mapping: dict[str, str] = {}
    for attr, val in vars(CharacteristicsTypes).items():
        if attr.startswith("_") or not isinstance(val, str):
            continue
        mapping[normalize_uuid(val)] = attr
    return mapping


_UUID_TO_NAME = _build_uuid_to_char_name()


def characteristic_label(type_uuid: str) -> str:
    nu = normalize_uuid(type_uuid)
    return _UUID_TO_NAME.get(nu, nu)


def _parse_char_name_to_uuid(spec: str) -> str:
    spec = spec.strip()
    if hasattr(CharacteristicsTypes, spec):
        return normalize_uuid(getattr(CharacteristicsTypes, spec))
    return normalize_uuid(spec)


def _resolve_aid_iid(pairing, char_spec: str) -> Optional[tuple[int, int]]:
    uid = _parse_char_name_to_uuid(char_spec)
    if not pairing.accessories:
        return None
    for acc in pairing.accessories:
        for svc in acc.services:
            for ch in svc.characteristics:
                if normalize_uuid(ch.type) == uid:
                    return acc.aid, ch.iid
    return None


def _subscribable_characteristics(pairing) -> list[tuple[int, int]]:
    out: list[tuple[int, int]] = []
    if not pairing.accessories:
        return out
    for acc in pairing.accessories:
        aid = acc.aid
        for svc in acc.services:
            for ch in svc.characteristics:
                if CharacteristicPermissions.events in ch.perms:
                    out.append((aid, ch.iid))
    return out


class HomeKitHubBridge:
    """One pairing, one WebSocket server, fan-out events."""

    def __init__(
        self,
        logger: logging.Logger,
        get_params: Callable[[], dict[str, Any]],
        get_custom_data: Callable[[], dict[str, Any]],
        set_custom_data: Callable[[dict[str, Any]], None],
    ) -> None:
        self.log = logger
        self._get_params = get_params
        self._get_custom_data = get_custom_data
        self._set_custom_data = set_custom_data

        self._hk: Optional[HKController] = None
        self._pairing_alias = PAIRING_ALIAS
        self._stop_listening: Optional[Callable[[], None]] = None
        self._clients: set[Any] = set()
        self._ws_server: Any = None
        self._running = False

    def _pairing(self):
        if not self._hk:
            return None
        return self._hk.aliases.get(self._pairing_alias)

    async def start(self) -> None:
        if self._running:
            return
        self._running = True
        self._hk = HKController()
        await self._hk.async_start()
        await self._start_websocket_server()
        await self._sync_pairing_from_params()

    async def stop(self) -> None:
        self._running = False
        if self._stop_listening:
            try:
                self._stop_listening()
            except Exception:
                pass
            self._stop_listening = None
        await self._shutdown_pairing_session()
        if self._ws_server is not None:
            self._ws_server.close()
            await self._ws_server.wait_closed()
            self._ws_server = None
        if self._hk:
            await self._hk.async_stop()
            self._hk = None
        self._clients.clear()

    async def restart_session(self) -> None:
        """Reload pairing from params + customData (after PG3 param change)."""
        if not self._running or not self._hk:
            return
        if self._stop_listening:
            try:
                self._stop_listening()
            except Exception:
                pass
            self._stop_listening = None
        await self._shutdown_pairing_session()
        await self._sync_pairing_from_params()

    async def discover_log(self, timeout: float = 12.0) -> None:
        if not self._hk:
            return
        self.log.info("HomeKit discovery (%.1fs)...", timeout)

        async def _scan() -> None:
            async for discovery in self._hk.async_discover():
                d = discovery.description
                if not d:
                    continue
                paired = discovery.paired
                self.log.info(
                    "HAP accessory: name=%r id=%s paired=%s",
                    d.name,
                    d.id,
                    paired,
                )

        try:
            await asyncio.wait_for(_scan(), timeout=timeout)
        except asyncio.TimeoutError:
            self.log.info("Discovery window ended")
        except Exception:
            self.log.exception("Discovery failed")

    def _ws_bind(self) -> tuple[str, int]:
        p = self._get_params()
        host = (p.get("ws_host") or "127.0.0.1").strip()
        try:
            port = int(p.get("ws_port") or 8163)
        except (TypeError, ValueError):
            port = 8163
        return host, port

    async def _start_websocket_server(self) -> None:
        host, port = self._ws_bind()
        self.log.info("WebSocket server listening on %s:%s", host, port)
        self._ws_server = await websockets.serve(
            self._ws_connection,
            host,
            port,
            ping_interval=20,
            ping_timeout=20,
        )

    async def _ws_connection(self, ws: Any) -> None:
        self._clients.add(ws)
        self.log.debug("WS client connected from %s", getattr(ws, "remote_address", None))
        try:
            async for raw in ws:
                await self._handle_ws_message(ws, raw)
        except websockets.ConnectionClosed:
            pass
        except Exception:
            self.log.exception("WebSocket handler error")
        finally:
            self._clients.discard(ws)

    async def _handle_ws_message(self, ws: Any, raw: str) -> None:
        try:
            msg = json.loads(raw)
        except json.JSONDecodeError:
            await self._send_ws(
                ws,
                {
                    "version": PROTOCOL_VERSION,
                    "action": "error",
                    "message": "invalid json",
                },
            )
            return
        ver = msg.get("version")
        if ver != PROTOCOL_VERSION:
            await self._send_ws(
                ws,
                {
                    "version": PROTOCOL_VERSION,
                    "action": "error",
                    "message": f"unsupported version {ver!r}, need {PROTOCOL_VERSION}",
                },
            )
            await ws.close()
            return
        action = msg.get("action")
        if action == "hello":
            await self._send_ws(
                ws,
                {
                    "version": PROTOCOL_VERSION,
                    "action": "ack",
                    "protocol": PROTOCOL_VERSION,
                },
            )
            return
        if action == "command":
            await self._handle_command(ws, msg)
            return
        await self._send_ws(
            ws,
            {
                "version": PROTOCOL_VERSION,
                "action": "error",
                "message": f"unknown action {action!r}",
            },
        )

    async def _handle_command(self, ws: Any, msg: dict) -> None:
        device_id = (msg.get("device_id") or "").strip().lower()
        char_spec = msg.get("characteristic")
        value = msg.get("value")
        pairing = self._pairing()
        if not pairing:
            await self._send_ws(
                ws,
                {
                    "version": PROTOCOL_VERSION,
                    "action": "error",
                    "for": "command",
                    "message": "no active pairing",
                },
            )
            return
        if pairing.id.lower() != device_id:
            await self._send_ws(
                ws,
                {
                    "version": PROTOCOL_VERSION,
                    "action": "error",
                    "for": "command",
                    "message": "device_id mismatch",
                },
            )
            return
        if not isinstance(char_spec, str):
            await self._send_ws(
                ws,
                {
                    "version": PROTOCOL_VERSION,
                    "action": "error",
                    "for": "command",
                    "message": "characteristic must be string",
                },
            )
            return
        resolved = _resolve_aid_iid(pairing, char_spec)
        if not resolved:
            await self._send_ws(
                ws,
                {
                    "version": PROTOCOL_VERSION,
                    "action": "error",
                    "for": "command",
                    "message": f"unknown characteristic {char_spec!r}",
                },
            )
            return
        aid, iid = resolved
        try:
            err = await pairing.put_characteristics([(aid, iid, value)])
            if err:
                await self._send_ws(
                    ws,
                    {
                        "version": PROTOCOL_VERSION,
                        "action": "error",
                        "for": "command",
                        "message": str(err),
                    },
                )
                return
        except Exception as ex:
            self.log.exception("put_characteristics failed")
            await self._send_ws(
                ws,
                {
                    "version": PROTOCOL_VERSION,
                    "action": "error",
                    "for": "command",
                    "message": str(ex),
                },
            )
            return
        await self._send_ws(
            ws,
            {"version": PROTOCOL_VERSION, "action": "ack", "for": "command"},
        )

    async def _send_ws(self, ws: Any, obj: dict) -> None:
        try:
            await ws.send(json.dumps(obj, default=str))
        except Exception:
            pass

    async def _broadcast(self, obj: dict) -> None:
        line = json.dumps(obj, default=str)
        dead: list[Any] = []
        for ws in list(self._clients):
            try:
                await ws.send(line)
            except Exception:
                dead.append(ws)
        for ws in dead:
            self._clients.discard(ws)

    def _on_hap_event(self, ev: dict) -> None:
        pairing = self._pairing()
        if not pairing or not pairing.accessories:
            return
        if not ev:
            return
        device_id = pairing.id.lower()
        try:
            loop = asyncio.get_running_loop()
        except RuntimeError:
            return

        for key, payload in ev.items():
            if not isinstance(key, tuple) or len(key) != 2:
                continue
            aid, iid = key
            if "value" not in payload:
                continue
            try:
                ch = pairing.accessories.aid(aid).characteristics.iid(iid)
                label = characteristic_label(ch.type)
            except Exception:
                label = f"{aid}.{iid}"
            loop.create_task(
                self._broadcast(
                    {
                        "version": PROTOCOL_VERSION,
                        "action": "event",
                        "device_id": device_id,
                        "characteristic": label,
                        "aid": aid,
                        "iid": iid,
                        "value": payload.get("value"),
                    }
                )
            )

    async def _shutdown_pairing_session(self) -> None:
        """Drop local controller state for the pairing alias (does not unpair accessory)."""
        if not self._hk:
            return
        pairing = self._hk.aliases.pop(self._pairing_alias, None)
        if pairing:
            pid = pairing.id
            self._hk.pairings.pop(pid, None)
            try:
                await pairing.close()
            except Exception:
                self.log.exception("pairing close")

    async def _sync_pairing_from_params(self) -> None:
        params = self._get_params()
        pin = (params.get("hap_pin") or "").strip()
        data = self._get_custom_data()
        saved = data.get(DATA_KEY_PAIRING)

        if not pin:
            if self._stop_listening:
                try:
                    self._stop_listening()
                except Exception:
                    pass
                self._stop_listening = None
            if self._hk and isinstance(saved, dict) and saved.get("AccessoryPairingID"):
                try:
                    if self._pairing_alias not in self._hk.aliases:
                        self._hk.load_pairing(self._pairing_alias, saved)
                    await self._hk.remove_pairing(self._pairing_alias)
                except Exception:
                    self.log.warning(
                        "Could not remove HomeKit pairing from accessory (offline or already removed)",
                        exc_info=True,
                    )
            self._clear_saved_pairing()
            await self._shutdown_pairing_session()
            return

        if saved and isinstance(saved, dict) and saved.get("AccessoryPairingID"):
            try:
                self._hk.load_pairing(self._pairing_alias, saved)
                pairing = self._pairing()
                if pairing:
                    await self._activate_pairing(pairing)
                return
            except Exception:
                self.log.exception("load_pairing failed; try new pairing")
                self._clear_saved_pairing()

        await self._pair_with_pin(pin, params)

    def _clear_saved_pairing(self) -> None:
        data = dict(self._get_custom_data())
        data.pop(DATA_KEY_PAIRING, None)
        self._set_custom_data(data)

    async def _pair_with_pin(self, pin: str, params: dict) -> None:
        accessory_id = (params.get("accessory_id") or "").strip().lower()
        accessory_name = (params.get("accessory_name") or "").strip()
        matched = None

        async def _find_first() -> Any:
            nonlocal matched
            async for discovery in self._hk.async_discover():
                d = discovery.description
                if not d:
                    continue
                if accessory_id and d.id.lower() != accessory_id:
                    continue
                if accessory_name and accessory_name.lower() not in (d.name or "").lower():
                    continue
                if discovery.paired:
                    self.log.warning(
                        "Skipping %s (%s): already paired; unpair in HomeKit first",
                        d.name,
                        d.id,
                    )
                    continue
                matched = discovery
                return discovery
            return None

        try:
            await asyncio.wait_for(_find_first(), timeout=30)
        except asyncio.TimeoutError:
            self.log.error("Pairing discovery timed out")
            return

        if not matched:
            self.log.error(
                "No unpaired HomeKit accessory matched id=%r name=%r",
                accessory_id,
                accessory_name,
            )
            return

        try:
            finish = await matched.async_start_pairing(self._pairing_alias)
            pairing = await finish(pin)
        except Exception:
            self.log.exception("Pairing failed")
            return

        pdata = dict(pairing.pairing_data)
        self._persist_pairing(pdata)
        await self._activate_pairing(pairing)

    def _persist_pairing(self, pdata: dict) -> None:
        data = dict(self._get_custom_data())
        data[DATA_KEY_PAIRING] = pdata
        self._set_custom_data(data)
        self.log.info("Saved pairing for accessory %s", pdata.get("AccessoryPairingID"))

    async def _activate_pairing(self, pairing) -> None:
        if self._stop_listening:
            try:
                self._stop_listening()
            except Exception:
                pass
        self._stop_listening = pairing.dispatcher_connect(self._on_hap_event)
        try:
            await pairing.list_accessories_and_characteristics()
        except Exception:
            self.log.exception("list_accessories_and_characteristics")
            return
        to_sub = _subscribable_characteristics(pairing)
        if to_sub:
            try:
                await pairing.subscribe(to_sub)
                self.log.info("Subscribed to %d event characteristics", len(to_sub))
            except Exception:
                self.log.exception("subscribe failed")
        self.log.info("HomeKit session active for %s", pairing.id)

"""
Async HomeKit controller + WebSocket bridge for PG3x.

Runs on a dedicated asyncio loop (see nodes.Controller). No udi_interface imports.

Supports multiple simultaneous pairings (fixed slot count); see PAIRING_SLOT_COUNT.
"""
from __future__ import annotations

import asyncio
import json
import logging
from typing import Any, Callable, Optional

import websockets

from aiohomekit import Controller as HKController
from aiohomekit.model.characteristics import CharacteristicPermissions, CharacteristicsTypes
from aiohomekit.model.status_flags import StatusFlags
from aiohomekit.uuid import normalize_uuid

PROTOCOL_VERSION = "1"
PAIRING_SLOT_COUNT = 8
DATA_KEY_PAIRINGS = "homekit_pairings"
LEGACY_DATA_KEY_PAIRING = "homekit_pairing"


def slot_alias(slot_num: int) -> str:
    return f"slot_{slot_num}"


def _build_uuid_to_char_name() -> dict[str, str]:
    mapping: dict[str, str] = {}
    for attr, val in vars(CharacteristicsTypes).items():
        if attr.startswith("_") or not isinstance(val, str):
            continue
        mapping[normalize_uuid(val)] = attr
    return mapping


_UUID_TO_NAME = _build_uuid_to_char_name()


def characteristic_label(type_uuid: str) -> str:
    nu = normalize_uuid(type_uuid)
    return _UUID_TO_NAME.get(nu, nu)


def _parse_char_name_to_uuid(spec: str) -> str:
    spec = spec.strip()
    if hasattr(CharacteristicsTypes, spec):
        return normalize_uuid(getattr(CharacteristicsTypes, spec))
    return normalize_uuid(spec)


def _resolve_aid_iid(pairing, char_spec: str) -> Optional[tuple[int, int]]:
    uid = _parse_char_name_to_uuid(char_spec)
    if not pairing.accessories:
        return None
    for acc in pairing.accessories:
        for svc in acc.services:
            for ch in svc.characteristics:
                if normalize_uuid(ch.type) == uid:
                    return acc.aid, ch.iid
    return None


def _subscribable_characteristics(pairing) -> list[tuple[int, int]]:
    out: list[tuple[int, int]] = []
    if not pairing.accessories:
        return out
    for acc in pairing.accessories:
        aid = acc.aid
        for svc in acc.services:
            for ch in svc.characteristics:
                if CharacteristicPermissions.events in ch.perms:
                    out.append((aid, ch.iid))
    return out


def slot_params_from_hub_params(slot_num: int, params: dict[str, Any]) -> tuple[str, str, str]:
    """Return (pin, accessory_id, accessory_name) for a slot; slot 1 also reads unsuffixed legacy keys."""
    pin = (params.get(f"hap_pin_{slot_num}") or "").strip()
    acc_id = (params.get(f"accessory_id_{slot_num}") or "").strip().lower()
    acc_name = (params.get(f"accessory_name_{slot_num}") or "").strip()
    if slot_num == 1:
        if not pin:
            pin = (params.get("hap_pin") or "").strip()
        if not acc_id:
            acc_id = (params.get("accessory_id") or "").strip().lower()
        if not acc_name:
            acc_name = (params.get("accessory_name") or "").strip()
    return pin, acc_id, acc_name


def pairing_snapshot_param_keys() -> list[str]:
    """Keys to watch for Polyglot param-change restart (includes legacy slot 1)."""
    keys = ["ws_host", "ws_port", "hap_pin", "accessory_id", "accessory_name"]
    for n in range(1, PAIRING_SLOT_COUNT + 1):
        keys.extend(
            [
                f"hap_pin_{n}",
                f"accessory_id_{n}",
                f"accessory_name_{n}",
            ]
        )
    return keys


class HomeKitHubBridge:
    """Multi-pairing HomeKit hub: WebSocket server + fan-out events."""

    def __init__(
        self,
        logger: logging.Logger,
        get_params: Callable[[], dict[str, Any]],
        get_custom_data: Callable[[], dict[str, Any]],
        set_custom_data: Callable[[dict[str, Any]], None],
    ) -> None:
        self.log = logger
        self._get_params = get_params
        self._get_custom_data = get_custom_data
        self._set_custom_data = set_custom_data

        self._hk: Optional[HKController] = None
        self._listeners: dict[str, Callable[[], None]] = {}
        self._clients: set[Any] = set()
        self._ws_server: Any = None
        self._running = False

    async def start(self) -> None:
        if self._running:
            return
        self._running = True
        self._hk = HKController()
        await self._hk.async_start()
        await self._start_websocket_server()
        await self._sync_pairing_from_params()

    async def stop(self) -> None:
        self._running = False
        self._clear_all_listeners()
        await self._shutdown_all_pairings()
        if self._ws_server is not None:
            self._ws_server.close()
            await self._ws_server.wait_closed()
            self._ws_server = None
        if self._hk:
            await self._hk.async_stop()
            self._hk = None
        self._clients.clear()

    async def restart_session(self) -> None:
        """Reload all slots from params + customData (after PG3 param change)."""
        if not self._running or not self._hk:
            return
        self._clear_all_listeners()
        await self._shutdown_all_pairings()
        await self._sync_pairing_from_params()

    def _clear_all_listeners(self) -> None:
        for stop in self._listeners.values():
            try:
                stop()
            except Exception:
                pass
        self._listeners.clear()

    async def _shutdown_all_pairings(self) -> None:
        if not self._hk:
            return
        for alias in list(self._hk.aliases.keys()):
            pairing = self._hk.aliases.pop(alias, None)
            if pairing:
                pid = pairing.id
                self._hk.pairings.pop(pid, None)
                try:
                    await pairing.close()
                except Exception:
                    self.log.exception("pairing close for %s", alias)

    async def discover_log(self, timeout: float = 12.0) -> None:
        if not self._hk:
            return
        self.log.info("HomeKit discovery (%.1fs)...", timeout)

        async def _scan() -> None:
            async for discovery in self._hk.async_discover():
                d = discovery.description
                if not d:
                    continue
                paired = discovery.paired
                self.log.info(
                    "HAP accessory: name=%r id=%s paired=%s",
                    d.name,
                    d.id,
                    paired,
                )

        try:
            await asyncio.wait_for(_scan(), timeout=timeout)
        except asyncio.TimeoutError:
            self.log.info("Discovery window ended")
        except Exception:
            self.log.exception("Discovery failed")

    def _ws_bind(self) -> tuple[str, int]:
        p = self._get_params()
        host = (p.get("ws_host") or "127.0.0.1").strip()
        try:
            port = int(p.get("ws_port") or 8163)
        except (TypeError, ValueError):
            port = 8163
        return host, port

    async def _start_websocket_server(self) -> None:
        host, port = self._ws_bind()
        self.log.info("WebSocket server listening on %s:%s", host, port)
        self._ws_server = await websockets.serve(
            self._ws_connection,
            host,
            port,
            ping_interval=20,
            ping_timeout=20,
        )

    async def _ws_connection(self, ws: Any) -> None:
        self._clients.add(ws)
        self.log.debug("WS client connected from %s", getattr(ws, "remote_address", None))
        try:
            async for raw in ws:
                await self._handle_ws_message(ws, raw)
        except websockets.ConnectionClosed:
            pass
        except Exception:
            self.log.exception("WebSocket handler error")
        finally:
            self._clients.discard(ws)

    async def _handle_ws_message(self, ws: Any, raw: str) -> None:
        try:
            msg = json.loads(raw)
        except json.JSONDecodeError:
            await self._send_ws(
                ws,
                {
                    "version": PROTOCOL_VERSION,
                    "action": "error",
                    "message": "invalid json",
                },
            )
            return
        ver = msg.get("version")
        if ver != PROTOCOL_VERSION:
            await self._send_ws(
                ws,
                {
                    "version": PROTOCOL_VERSION,
                    "action": "error",
                    "message": f"unsupported version {ver!r}, need {PROTOCOL_VERSION}",
                },
            )
            await ws.close()
            return
        action = msg.get("action")
        if action == "hello":
            await self._send_ws(
                ws,
                {
                    "version": PROTOCOL_VERSION,
                    "action": "ack",
                    "protocol": PROTOCOL_VERSION,
                },
            )
            return
        if action == "command":
            await self._handle_command(ws, msg)
            return
        await self._send_ws(
            ws,
            {
                "version": PROTOCOL_VERSION,
                "action": "error",
                "message": f"unknown action {action!r}",
            },
        )

    def _pairing_for_device_id(self, device_id: str):
        if not self._hk:
            return None
        return self._hk.pairings.get(device_id)

    async def _handle_command(self, ws: Any, msg: dict) -> None:
        device_id = (msg.get("device_id") or "").strip().lower()
        char_spec = msg.get("characteristic")
        value = msg.get("value")
        pairing = self._pairing_for_device_id(device_id) if device_id else None
        if not pairing:
            await self._send_ws(
                ws,
                {
                    "version": PROTOCOL_VERSION,
                    "action": "error",
                    "for": "command",
                    "message": "unknown device_id or no active pairing",
                },
            )
            return
        if not isinstance(char_spec, str):
            await self._send_ws(
                ws,
                {
                    "version": PROTOCOL_VERSION,
                    "action": "error",
                    "for": "command",
                    "message": "characteristic must be string",
                },
            )
            return
        resolved = _resolve_aid_iid(pairing, char_spec)
        if not resolved:
            await self._send_ws(
                ws,
                {
                    "version": PROTOCOL_VERSION,
                    "action": "error",
                    "for": "command",
                    "message": f"unknown characteristic {char_spec!r}",
                },
            )
            return
        aid, iid = resolved
        try:
            err = await pairing.put_characteristics([(aid, iid, value)])
            if err:
                await self._send_ws(
                    ws,
                    {
                        "version": PROTOCOL_VERSION,
                        "action": "error",
                        "for": "command",
                        "message": str(err),
                    },
                )
                return
        except Exception as ex:
            self.log.exception("put_characteristics failed")
            await self._send_ws(
                ws,
                {
                    "version": PROTOCOL_VERSION,
                    "action": "error",
                    "for": "command",
                    "message": str(ex),
                },
            )
            return
        await self._send_ws(
            ws,
            {"version": PROTOCOL_VERSION, "action": "ack", "for": "command"},
        )

    async def _send_ws(self, ws: Any, obj: dict) -> None:
        try:
            await ws.send(json.dumps(obj, default=str))
        except Exception:
            pass

    async def _broadcast(self, obj: dict) -> None:
        line = json.dumps(obj, default=str)
        dead: list[Any] = []
        for ws in list(self._clients):
            try:
                await ws.send(line)
            except Exception:
                dead.append(ws)
        for ws in dead:
            self._clients.discard(ws)

    def _dispatch_hap_event(self, device_id: str, pairing, ev: dict) -> None:
        if not pairing or not pairing.accessories:
            return
        if not ev:
            return
        try:
            loop = asyncio.get_running_loop()
        except RuntimeError:
            return

        for key, payload in ev.items():
            if not isinstance(key, tuple) or len(key) != 2:
                continue
            aid, iid = key
            if "value" not in payload:
                continue
            try:
                ch = pairing.accessories.aid(aid).characteristics.iid(iid)
                label = characteristic_label(ch.type)
            except Exception:
                label = f"{aid}.{iid}"
            loop.create_task(
                self._broadcast(
                    {
                        "version": PROTOCOL_VERSION,
                        "action": "event",
                        "device_id": device_id,
                        "characteristic": label,
                        "aid": aid,
                        "iid": iid,
                        "value": payload.get("value"),
                    }
                )
            )

    def _attach_listener(self, alias: str, pairing) -> None:
        if alias in self._listeners:
            try:
                self._listeners.pop(alias, None)()
            except Exception:
                pass
        device_id = pairing.id.lower()

        def _cb(ev: dict) -> None:
            self._dispatch_hap_event(device_id, pairing, ev)

        self._listeners[alias] = pairing.dispatcher_connect(_cb)

    def _get_pairings_blob(self) -> dict[str, Any]:
        data = self._get_custom_data()
        raw = data.get(DATA_KEY_PAIRINGS)
        if isinstance(raw, dict):
            return dict(raw)
        return {}

    def _migrate_legacy_pairing_storage(self) -> None:
        data = dict(self._get_custom_data())
        if LEGACY_DATA_KEY_PAIRING in data and DATA_KEY_PAIRINGS not in data:
            legacy = data.pop(LEGACY_DATA_KEY_PAIRING)
            if isinstance(legacy, dict) and legacy.get("AccessoryPairingID"):
                data[DATA_KEY_PAIRINGS] = {"1": legacy}
                self.log.info("Migrated legacy homekit_pairing to homekit_pairings[1]")
            self._set_custom_data(data)
        elif LEGACY_DATA_KEY_PAIRING in data and DATA_KEY_PAIRINGS in data:
            data.pop(LEGACY_DATA_KEY_PAIRING, None)
            self._set_custom_data(data)

    def _set_pairings_blob(self, blob: dict[str, Any]) -> None:
        data = dict(self._get_custom_data())
        data[DATA_KEY_PAIRINGS] = blob
        data.pop(LEGACY_DATA_KEY_PAIRING, None)
        self._set_custom_data(data)

    async def _sync_pairing_from_params(self) -> None:
        self._migrate_legacy_pairing_storage()
        params = self._get_params()
        blob = self._get_pairings_blob()

        for slot_num in range(1, PAIRING_SLOT_COUNT + 1):
            alias = slot_alias(slot_num)
            slot_key = str(slot_num)
            pin, acc_id, acc_name = slot_params_from_hub_params(slot_num, params)
            saved = blob.get(slot_key)
            if isinstance(saved, dict) and not saved.get("AccessoryPairingID"):
                saved = None

            if not pin:
                if saved and self._hk:
                    try:
                        if alias not in self._hk.aliases:
                            self._hk.load_pairing(alias, saved)
                        await self._hk.remove_pairing(alias)
                    except Exception:
                        self.log.warning(
                            "Slot %s: could not remove pairing from accessory",
                            slot_num,
                            exc_info=True,
                        )
                if slot_key in blob:
                    del blob[slot_key]
                    self._set_pairings_blob(blob)
                await self._close_alias_if_present(alias)
                continue

            if saved:
                try:
                    self._hk.load_pairing(alias, saved)
                    pairing = self._hk.aliases.get(alias)
                    if pairing:
                        await self._activate_pairing(alias, pairing)
                    continue
                except Exception:
                    self.log.exception("Slot %s: load_pairing failed; will try new pair", slot_num)
                    if slot_key in blob:
                        del blob[slot_key]
                        self._set_pairings_blob(blob)
                    await self._close_alias_if_present(alias)

            await self._pair_with_pin(slot_num, alias, pin, acc_id, acc_name, blob)

    async def _close_alias_if_present(self, alias: str) -> None:
        if not self._hk:
            return
        st = self._listeners.pop(alias, None)
        if st:
            try:
                st()
            except Exception:
                pass
        pairing = self._hk.aliases.pop(alias, None)
        if pairing:
            pid = pairing.id
            self._hk.pairings.pop(pid, None)
            try:
                await pairing.close()
            except Exception:
                self.log.exception("close %s", alias)

    async def _pair_with_pin(
        self,
        slot_num: int,
        alias: str,
        pin: str,
        accessory_id: str,
        accessory_name: str,
        blob: dict[str, Any],
    ) -> None:
        async def _find_first() -> Any:
            async for discovery in self._hk.async_discover():
                d = discovery.description
                if not d:
                    continue
                if accessory_id and d.id.lower() != accessory_id:
                    continue
                if accessory_name and accessory_name.lower() not in (d.name or "").lower():
                    continue
                if discovery.paired:
                    self.log.warning(
                        "Skipping %s (%s): already paired; unpair in HomeKit first",
                        d.name,
                        d.id,
                    )
                    continue
                return discovery
            return None

        try:
            matched = await asyncio.wait_for(_find_first(), timeout=30)
        except asyncio.TimeoutError:
            self.log.error("Slot %s: pairing discovery timed out", slot_num)
            return

        if not matched:
            self.log.error(
                "Slot %s: no unpaired accessory matched id=%r name=%r",
                slot_num,
                accessory_id,
                accessory_name,
            )
            return

        try:
            finish = await matched.async_start_pairing(alias)
            pairing = await finish(pin)
        except Exception:
            self.log.exception("Slot %s: pairing failed", slot_num)
            return

        pdata = dict(pairing.pairing_data)
        slot_key = str(slot_num)
        blob[slot_key] = pdata
        self._set_pairings_blob(blob)
        self.log.info(
            "Slot %s: saved pairing for accessory %s",
            slot_num,
            pdata.get("AccessoryPairingID"),
        )
        await self._activate_pairing(alias, pairing)

    async def _activate_pairing(self, alias: str, pairing) -> None:
        self._attach_listener(alias, pairing)
        try:
            await pairing.list_accessories_and_characteristics()
        except Exception:
            self.log.exception("list_accessories_and_characteristics for %s", alias)
            return
        to_sub = _subscribable_characteristics(pairing)
        if to_sub:
            try:
                await pairing.subscribe(to_sub)
                self.log.info(
                    "%s: subscribed to %d event characteristics",
                    alias,
                    len(to_sub),
                )
            except Exception:
                self.log.exception("subscribe failed for %s", alias)
        self.log.info("HomeKit session active for %s (%s)", alias, pairing.id)

